+    let parts: Vec<&str> = rest.split('_').collect();
+    // Need at least: version + timestamp + ws_key + host
+    if parts.len() < 4 {
+        return None;
+    }
+
+    // Workspace key is an 8-char hex segment generated by snapshot_filename.
+    // Scan from the right but require at least one segment for version/timestamp
+    // and one for host.
+    let ws_idx = parts.iter().enumerate().rev().find_map(|(idx, segment)| {
+        if idx == 0 || idx + 1 >= parts.len() {
+            return None;
+        }
+        let is_ws_key = segment.len() == 8 && segment.bytes().all(|b| b.is_ascii_hexdigit());
+        if is_ws_key { Some(idx) } else { None }
+    })?;
+
+    // Timestamp is either a single segment or date_time as two numeric segments.
+    let timestamp_start = if ws_idx >= 2
+        && parts[ws_idx - 1].len() == 6
+        && parts[ws_idx - 1].bytes().all(|b| b.is_ascii_digit())
+        && parts[ws_idx - 2].len() == 8
+        && parts[ws_idx - 2].bytes().all(|b| b.is_ascii_digit())
+    {
+        ws_idx - 2
     } else {
-        None
+        ws_idx - 1
+    };
+
+    if timestamp_start == 0 {
+        return None;
+    }
+
+    let version = parts[..timestamp_start].join("_");
+    let timestamp = parts[timestamp_start..ws_idx].join("_");
+    let ws_key = parts[ws_idx].to_string();
+    let host = parts[ws_idx + 1..].join("_");
+
+    if version.is_empty() || timestamp.is_empty() || ws_key.is_empty() || host.is_empty() {
+        return None;
     }
+
